#include<cstdio>
#include<cstring>
#define rep(a,b,c) for(int c=(a);c<=(b);++c)
#define drep(a,b,c) for(int c=(a);c>=(b);--c)
typedef unsigned long long LL;const LL Mod=7528443412579576937ll;
inline void DN(LL &x){x>=Mod?x-=Mod:0;}
inline LL Mul(LL a,LL b){LL r(0);while(b)b&1?DN(r+=a):void(),DN(a+=a),b=b>>1;return r;}
struct Matrix
{
	LL a[2][2];inline Matrix(){memset(a,0,sizeof(a));}
	inline Matrix friend operator * (Matrix a,Matrix b)
	{
		Matrix c;rep(0,1,k)rep(0,1,i)if(a.a[i][k])rep(0,1,j)if(b.a[k][j])
			DN(c.a[i][j]+=Mul(a.a[i][k],b.a[k][j])) ;return c;
	}
	inline Matrix friend operator ^ (Matrix a,long long b)
		{Matrix res;res.a[0][0]=res.a[1][1]=1;while(b){if(b&1)res=res*a;a=a*a;b=b>>1;};return res;}
}a;
int main()
{
	LL b,d,n;scanf("%lld%lld%lld",&b,&d,&n);if(!n)return putchar('1'),0;
	Matrix a;a.a[0][0]=0;a.a[0][1]=(d-b*b)/4;a.a[1][0]=1;a.a[1][1]=b;a=a^(n-1);
	LL ans=Mul(a.a[0][1],2)+Mul(a.a[1][1],b);DN(ans);if(d*d!=b&&!(n&1))--ans;printf("%lld\n",ans);
}
